"""
payments.py — Full billing backend (Updated)

Features:
  • POST   /payments                     — create payment, generate PDF receipt, write Excel row
  • GET    /payments/visit/<visit_id>    — list payments for a visit
  • GET    /payments                     — search payments
  • GET    /payments/<id>/receipt        — download PDF receipt
  • PUT    /payments/<id>               — edit payment, regenerate receipt, update Excel row
  • DELETE /payments/<id>               — delete payment + PDF + Excel row; receipt number recycled
  • GET    /billing/closed-visits        — visits ready for billing

Excel columns (updated):
    date, receipt_no, name, case_no, mobile, advice, treatment_plan,
    treatment_description, all_treatment_costs, discount, amount_paid,
    payment_method, balance

PDF receipt: clinic logo + improved typography + clean signature.
"""

from flask import Blueprint, request, jsonify, send_file, current_app
from datetime import datetime, date
from sqlalchemy import or_
import os, io, json

from database import db
from models import Payment, Visit, Patient

payments_bp = Blueprint("payments", __name__)

# ── Embedded images (base64) — no external file dependency ──
import base64 as _b64, tempfile as _tmp

FLASK_ROOT    = os.path.abspath(os.path.join(os.path.dirname(__file__), ".."))
RECEIPTS_ROOT = os.path.join(FLASK_ROOT, "receipts")

_LOGO_B64 = ""
_SIG_B64  = ""

def _img_from_b64(b64_str, width, height):
    from reportlab.platypus import Image as _RLImage
    data = _b64.b64decode(b64_str)
    t = _tmp.NamedTemporaryFile(suffix='.png', delete=False)
    t.write(data); t.flush(); t.close()
    return _RLImage(t.name, width=width, height=height)

# ══════════════════════════════════════════════════════════════════
#  EXCEL HELPERS
# ══════════════════════════════════════════════════════════════════
EXCEL_HEADERS = [
    "date", "receipt_no", "name", "case_no", "mobile",
    "advice", "treatment_plan", "treatment_description",
    "all_treatment_costs", "discount", "amount_paid",
    "payment_method", "balance",
]


def _excel_folder(dt: date):
    month_name = dt.strftime("%B")
    year       = dt.year
    month_year = f"{month_name}{year}"
    if dt.month >= 4:
        fy = f"FY{dt.year}-{str(dt.year+1)[2:]}"
    else:
        fy = f"FY{dt.year-1}-{str(dt.year)[2:]}"
    folder = os.path.join(RECEIPTS_ROOT, fy, month_year)
    os.makedirs(folder, exist_ok=True)
    return folder, month_year


def _excel_path(dt: date) -> str:
    folder, month_year = _excel_folder(dt)
    return os.path.join(folder, f"{month_year}.xlsx")


def _load_or_create_wb(path: str):
    import openpyxl
    from openpyxl.styles import Font, PatternFill, Alignment, Border, Side
    from openpyxl.utils import get_column_letter

    if os.path.exists(path):
        wb = openpyxl.load_workbook(path)
        ws = wb.active
    else:
        wb = openpyxl.Workbook()
        ws = wb.active
        ws.title = "Payments"
        navy = "0B2D4E"
        for col, hdr in enumerate(EXCEL_HEADERS, 1):
            cell = ws.cell(row=1, column=col, value=hdr)
            cell.font      = Font(bold=True, color="FFFFFF", size=10, name="Calibri")
            cell.fill      = PatternFill("solid", fgColor=navy)
            cell.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)
            cell.border    = Border(
                bottom=Side(style="thin", color="FFFFFF"),
                right=Side(style="thin", color="FFFFFF"),
            )
        ws.row_dimensions[1].height = 22
        widths = [12, 10, 22, 12, 14, 28, 28, 38, 20, 10, 12, 16, 12]
        for i, w in enumerate(widths, 1):
            ws.column_dimensions[get_column_letter(i)].width = w
    return wb, ws


def _treatment_costs_str(treatments: list) -> str:
    """Return a readable per-treatment cost string: 'Consultation: ₹400, RCT: ₹2000'"""
    parts = []
    for t in treatments:
        desc = (t.get("description") or "").split("\n")[0].strip()
        amt  = t.get("amount", 0)
        if desc:
            parts.append(f"{desc}: ₹{int(float(amt or 0)):,}")
    return ", ".join(parts) if parts else ""


def _build_excel_row(payment, visit_data: dict, treatments: list):
    dt = _payment_date(payment)
    return [
        dt.strftime("%Y-%m-%d"),
        payment.receipt_number,
        payment.patient_name,
        payment.case_number,
        payment.mobile,
        visit_data.get("advice", ""),
        visit_data.get("treatment_plan", ""),
        _flat_treatment_names(treatments),
        _treatment_costs_str(treatments),
        payment.discount or 0,
        payment.paid_amount,
        payment.payment_method,
        payment.balance or 0,
    ]


def _flat_treatment_names(treatments: list) -> str:
    return ", ".join(
        (t.get("description") or "").split("\n")[0].strip()
        for t in treatments if t.get("description")
    )


def _append_excel_row(payment, visit_data: dict, treatments: list):
    dt   = _payment_date(payment)
    path = _excel_path(dt)
    wb, ws = _load_or_create_wb(path)
    row = _build_excel_row(payment, visit_data, treatments)
    ws.append(row)
    wb.save(path)


def _update_excel_row(payment, visit_data: dict, treatments: list):
    dt   = _payment_date(payment)
    path = _excel_path(dt)
    if not os.path.exists(path):
        _append_excel_row(payment, visit_data, treatments)
        return
    import openpyxl
    wb = openpyxl.load_workbook(path)
    ws = wb.active
    new_vals = _build_excel_row(payment, visit_data, treatments)
    for row in ws.iter_rows(min_row=2):
        if row[1].value == payment.receipt_number:  # col B = receipt_no
            for i, v in enumerate(new_vals):
                row[i].value = v
            break
    wb.save(path)


def _delete_excel_row(payment):
    dt   = _payment_date(payment)
    path = _excel_path(dt)
    if not os.path.exists(path):
        return
    import openpyxl
    wb = openpyxl.load_workbook(path)
    ws = wb.active
    for i, row in enumerate(ws.iter_rows(min_row=2), start=2):
        if row[1].value == payment.receipt_number:
            ws.delete_rows(i)
            break
    wb.save(path)


def _payment_date(payment) -> date:
    if payment.payment_date:
        return payment.payment_date
    if payment.created_at:
        return payment.created_at.date()
    return date.today()


# ══════════════════════════════════════════════════════════════════
#  RECEIPT NUMBER — reusable pool
# ══════════════════════════════════════════════════════════════════
def _next_receipt_number() -> int:
    """
    Returns the lowest unused receipt number.
    Deleted receipt numbers are recycled — they re-enter the pool.
    """
    used = {
        r[0]
        for r in db.session.query(Payment.receipt_number)
        .filter(Payment.receipt_number.isnot(None))
        .all()
    }
    n = 1
    while n in used:
        n += 1
    return n


# ══════════════════════════════════════════════════════════════════
#  NUMBER → WORDS
# ══════════════════════════════════════════════════════════════════
def _num_to_words(n):
    ones = ['','One','Two','Three','Four','Five','Six','Seven','Eight','Nine',
            'Ten','Eleven','Twelve','Thirteen','Fourteen','Fifteen','Sixteen',
            'Seventeen','Eighteen','Nineteen']
    tens = ['','','Twenty','Thirty','Forty','Fifty','Sixty','Seventy','Eighty','Ninety']
    def h(n):
        if n == 0: return ''
        elif n < 20: return ones[n]
        elif n < 100: return tens[n//10]+(' '+ones[n%10] if n%10 else '')
        elif n < 1000: return ones[n//100]+' Hundred'+(' '+h(n%100) if n%100 else '')
        elif n < 100000: return h(n//1000)+' Thousand'+(' '+h(n%1000) if n%1000 else '')
        elif n < 10000000: return h(n//100000)+' Lakh'+(' '+h(n%100000) if n%100000 else '')
        else: return h(n//10000000)+' Crore'+(' '+h(n%10000000) if n%10000000 else '')
    n = int(float(n))
    return 'Zero' if n == 0 else h(n)


# ══════════════════════════════════════════════════════════════════
#  PDF RECEIPT GENERATOR  (updated design)
# ══════════════════════════════════════════════════════════════════
def _generate_receipt_pdf(payment, treatments: list, visit_data: dict = None) -> bytes:
    from reportlab.lib.pagesizes import A4
    from reportlab.lib import colors
    from reportlab.lib.units import mm
    from reportlab.platypus import (SimpleDocTemplate, Table, TableStyle,
                                    Paragraph, Spacer, Image, HRFlowable)
    from reportlab.lib.styles import ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_RIGHT, TA_LEFT

    visit_data = visit_data or {}
    W, H = A4
    LM = RM = 20 * mm
    CW = W - LM - RM

    # ── Colors ──
    navy      = colors.HexColor("#0B2D4E")
    lightblue = colors.HexColor("#EFF6FF")
    gray      = colors.HexColor("#64748B")
    lgray     = colors.HexColor("#F8FAFC")
    rulecol   = colors.HexColor("#BFDBFE")

    def sty(size, bold=False, color=colors.black, align=TA_LEFT, leading=None):
        fn = "Helvetica-Bold" if bold else "Helvetica"
        return ParagraphStyle("_", fontSize=size, fontName=fn, textColor=color,
                              alignment=align, leading=leading or size * 1.45,
                              spaceAfter=0, spaceBefore=0)

    buf = io.BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4,
        topMargin=14*mm, bottomMargin=16*mm,
        leftMargin=LM, rightMargin=RM)

    # ── Page border callback ──
    def _draw_border(canvas, doc):
        canvas.saveState()
        canvas.setStrokeColor(navy)
        canvas.setLineWidth(1.5)
        canvas.rect(10*mm, 10*mm, W - 20*mm, H - 20*mm, stroke=1, fill=0)
        canvas.restoreState()

    story = []

    # ── HEADER: logo + clinic name side by side ──
    logo_cell = _img_from_b64(_LOGO_B64, 28*mm, 28*mm)

    header_data = [[
        logo_cell,
        [
            Paragraph('<b>Sri Satya Sai Oral Health Center &amp; Dental Clinic</b>',
                      sty(15, bold=True, color=colors.HexColor("#C0001A"), align=TA_LEFT)),
            Spacer(1, 1.5*mm),
            Paragraph('<b>Address:</b> G-15, Rajnigandha Apartments, Chaitanyapuri, Hyderabad - 500060',
                      sty(9.5, color=gray)),
            Paragraph('<b>Ph:</b> 040-66718100 &nbsp;|&nbsp; 9949094449',
                      sty(9.5, color=gray)),
        ]
    ]]
    story.append(Table(header_data,
        colWidths=[32*mm, CW - 32*mm],
        style=TableStyle([
            ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
            ("LEFTPADDING", (0, 0), (0, 0), 0),
            ("RIGHTPADDING", (0, 0), (0, 0), 4),
            ("LEFTPADDING", (1, 0), (1, 0), 6),
        ])))
    story.append(Spacer(1, 3*mm))
    story.append(HRFlowable(width="100%", thickness=2, color=navy, spaceAfter=0))
    story.append(Spacer(1, 2*mm))

    # ── RECEIPT title bar ──
    story.append(Table([[
        Paragraph("", sty(8)),
        Paragraph("<b>RECEIPT</b>", sty(15, bold=True, color=navy, align=TA_CENTER)),
        Paragraph("", sty(8)),
    ]], colWidths=[CW*0.25, CW*0.5, CW*0.25],
    style=TableStyle([("ALIGN", (1, 0), (1, 0), "CENTER")])))
    story.append(Spacer(1, 3*mm))

    # ── Date + Receipt No ──
    dt       = _payment_date(payment)
    date_str = dt.strftime("%d-%b-%Y")
    story.append(Table([[
        Paragraph(f"Date: <b>{date_str}</b>",              sty(11)),
        Paragraph(f"Receipt No: <b>{payment.receipt_number}</b>", sty(11, align=TA_RIGHT)),
    ]], colWidths=[CW / 2, CW / 2],
    style=TableStyle([
        ("ALIGN",   (1, 0), (1, 0), "RIGHT"),
        ("VALIGN",  (0, 0), (-1, -1), "MIDDLE"),
    ])))
    story.append(Spacer(1, 4*mm))

    # ── Patient info table ──
    story.append(Table([
        [Paragraph("<b>Name</b>",    sty(11, color=gray)), Paragraph(payment.patient_name or "", sty(11))],
        [Paragraph("<b>Case Id</b>", sty(11, color=gray)), Paragraph(str(payment.case_number or ""), sty(11))],
        [Paragraph("<b>Mobile</b>",  sty(11, color=gray)), Paragraph(str(payment.mobile or ""), sty(11))],
    ], colWidths=[30*mm, CW - 30*mm],
    style=TableStyle([
        ("TOPPADDING",    (0, 0), (-1, -1), 4),
        ("BOTTOMPADDING", (0, 0), (-1, -1), 4),
        ("LINEBELOW",     (0, -1), (-1, -1), 0.4, colors.HexColor("#E2E8F0")),
    ])))
    story.append(Spacer(1, 4*mm))

    # ── Advice / Treatment Plan — skip "visit once in 6 months" boilerplate ──
    advice = visit_data.get("advice", "") or ""
    tplan  = visit_data.get("treatment_plan", "") or ""

    def _is_footer_text(t):
        return "visit once in 6 months" in (t or "").strip().lower() or not (t or "").strip()

    filtered_advice = "" if _is_footer_text(advice) else advice
    filtered_tplan  = tplan.strip()

    if filtered_advice or filtered_tplan:
        advice_rows = []
        if filtered_advice:
            advice_rows.append([
                Paragraph("<b>Advice</b>",         sty(10, color=gray)),
                Paragraph(filtered_advice,           sty(10)),
            ])
        if filtered_tplan:
            advice_rows.append([
                Paragraph("<b>Treatment Plan</b>", sty(10, color=gray)),
                Paragraph(filtered_tplan,            sty(10)),
            ])
        story.append(Table(advice_rows, colWidths=[32*mm, CW - 32*mm],
            style=TableStyle([
                ("TOPPADDING",    (0, 0), (-1, -1), 4),
                ("BOTTOMPADDING", (0, 0), (-1, -1), 4),
                ("BACKGROUND",    (0, 0), (-1, -1), lightblue),
                ("LINEBELOW",     (0, -1), (-1, -1), 0.4, rulecol),
            ])))
        story.append(Spacer(1, 4*mm))

    # ── Treatments table ──
    story.append(Paragraph("<b>Treatments</b>", sty(11, bold=True, color=navy)))
    story.append(Spacer(1, 2*mm))

    hdr_style = sty(10, bold=True, color=colors.white)
    rows = [[
        Paragraph("<b>No</b>",                       hdr_style),
        Paragraph("<b>Treatment &amp; Description</b>", hdr_style),
        Paragraph("<b>Amount (&#8377;)</b>",          ParagraphStyle("_", fontSize=10,
            fontName="Helvetica-Bold", textColor=colors.white,
            alignment=TA_RIGHT, leading=14)),
    ]]
    for i, t in enumerate(treatments, 1):
        desc = str(t.get("description", "")).replace("\n", "<br/>")
        amt  = float(t.get("amount", 0) or 0)
        rows.append([
            Paragraph(str(i), sty(10)),
            Paragraph(desc,   sty(10)),
            Paragraph(f"{amt:,.2f}", ParagraphStyle("_", fontSize=10,
                fontName="Helvetica", alignment=TA_RIGHT, leading=14)),
        ])

    story.append(Table(rows,
        colWidths=[12*mm, CW - 42*mm, 30*mm],
        style=TableStyle([
            ("BACKGROUND",    (0, 0), (-1, 0),  navy),
            ("ROWBACKGROUNDS",(0, 1), (-1, -1), [colors.white, lgray]),
            ("GRID",          (0, 0), (-1, -1),  0.4, colors.HexColor("#CBD5E1")),
            ("ALIGN",         (2, 0), (2, -1),  "RIGHT"),
            ("VALIGN",        (0, 0), (-1, -1), "MIDDLE"),
            ("TOPPADDING",    (0, 0), (-1, -1),  6),
            ("BOTTOMPADDING", (0, 0), (-1, -1),  6),
            ("LEFTPADDING",   (0, 0), (-1, -1),  6),
            ("RIGHTPADDING",  (0, 0), (-1, -1),  6),
            ("FONTNAME",      (0, 0), (-1, 0),  "Helvetica-Bold"),
        ])))
    story.append(Spacer(1, 4*mm))

    # ── Totals block ──
    total    = float(payment.paid_amount or 0)
    disc     = float(payment.discount or 0)
    fee      = float(payment.fee or total + disc)
    balance  = float(payment.balance or 0)

    totals_data = []
    if disc > 0:
        totals_data.append([
            Paragraph("Total Fee:", sty(10, color=gray, align=TA_RIGHT)),
            Paragraph(f"&#8377; {fee:,.2f}",      sty(10, align=TA_RIGHT)),
        ])
        totals_data.append([
            Paragraph("Discount:", sty(10, color=gray, align=TA_RIGHT)),
            Paragraph(f"- &#8377; {disc:,.2f}",   sty(10, align=TA_RIGHT)),
        ])
    totals_data.append([
        Paragraph("<b>Total:</b>", sty(12, bold=True, color=navy, align=TA_RIGHT)),
        Paragraph(f"<b>&#8377; {total:,.2f}</b>",  sty(12, bold=True, color=navy, align=TA_RIGHT)),
    ])
    if balance > 0:
        totals_data.append([
            Paragraph("Balance Due:", sty(10, color=colors.HexColor("#DC2626"), align=TA_RIGHT)),
            Paragraph(f"&#8377; {balance:,.2f}",
                      sty(10, color=colors.HexColor("#DC2626"), align=TA_RIGHT)),
        ])

    story.append(Table(totals_data,
        colWidths=[CW - 42*mm, 42*mm],
        style=TableStyle([
            ("ALIGN",  (0, 0), (-1, -1), "RIGHT"),
            ("TOPPADDING",    (0, 0), (-1, -1), 3),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 3),
        ])))
    story.append(Spacer(1, 3*mm))

    story.append(HRFlowable(width="100%", thickness=0.6, color=rulecol))
    story.append(Spacer(1, 2.5*mm))
    story.append(Paragraph(
        f"<b>Amount in Words: Rupees {_num_to_words(total)} Only</b>",
        sty(10, color=gray)))
    story.append(Spacer(1, 2.5*mm))
    story.append(Paragraph(
        f"Payment Method(s): <b>{payment.payment_method or ''}</b>",
        sty(10)))
    story.append(Spacer(1, 10*mm))

    # ── Signature ──
    sig_w = CW * 0.42
    left_w = CW - sig_w

    story.append(Table([[
        "",
        _img_from_b64(_SIG_B64, 30*mm, 15*mm),
    ]], colWidths=[left_w, sig_w],
    style=TableStyle([
        ("ALIGN",  (1, 0), (1, 0), "RIGHT"),
        ("VALIGN", (0, 0), (-1, -1), "BOTTOM"),
    ])))

    story.append(Table([[
        "",
        Paragraph("<b>Authorized Signatory</b>", sty(10, bold=True, align=TA_RIGHT)),
    ]], colWidths=[left_w, sig_w],
    style=TableStyle([("ALIGN", (1, 0), (1, 0), "RIGHT")])))

    story.append(Spacer(1, 8*mm))
    story.append(HRFlowable(width="100%", thickness=0.5,
                            color=colors.HexColor("#E2E8F0")))
    story.append(Spacer(1, 3*mm))
    story.append(Paragraph(
        "<i>Visit once in 6 months or as advised by the doctor to maintain better oral health</i>",
        sty(8, color=gray, align=TA_CENTER)))

    doc.build(story, onFirstPage=_draw_border, onLaterPages=_draw_border)
    buf.seek(0)
    return buf.read()


def _save_receipt_pdf(payment, treatments: list, visit_data: dict = None) -> str:
    dt         = _payment_date(payment)
    folder, _  = _excel_folder(dt)
    filename   = f"receipt_{payment.receipt_number}_{payment.patient_name.replace(' ', '_')}.pdf"
    filepath   = os.path.join(folder, filename)
    pdf_bytes  = _generate_receipt_pdf(payment, treatments, visit_data)
    with open(filepath, "wb") as f:
        f.write(pdf_bytes)
    return filepath


# ══════════════════════════════════════════════════════════════════
#  VISIT DATA HELPER
# ══════════════════════════════════════════════════════════════════
def _visit_data(visit_id) -> dict:
    visit = Visit.query.get(visit_id)
    if not visit:
        return {}
    from models import Consultation
    c = (Consultation.query
         .filter_by(visit_id=visit_id)
         .order_by(Consultation.created_at.desc())
         .first())
    # Prefer denormalised snapshot written on the Visit row at close time;
    # fall back to live Consultation values so older visits still work.
    return {
        "billing_note":   getattr(visit, "billing_note",   "") or "",
        "treatment_done": (getattr(visit, "treatment_done", "") or
                           (c.treatment_done_today if c else "")) or "",
        "treatment_plan": (getattr(visit, "treatment_plan", "") or
                           (c.treatment_plan if c else "")) or "",
        "advice":         (getattr(visit, "advice",         "") or
                           (c.advice        if c else "")) or "",
        "diagnosis":      (getattr(visit, "diagnosis",      "") or
                           (c.diagnosis     if c else "")) or "",
    }


def _parse_treatments(payment) -> list:
    """Parse treatment_description JSON or fall back to plain string."""
    try:
        arr = json.loads(payment.treatment_description or "[]")
        if isinstance(arr, list) and arr:
            return arr
    except Exception:
        pass
    return [{"description": payment.treatment_description or "", "amount": payment.paid_amount}]



# ══════════════════════════════════════════════════════════════════
#  SERIALIZER
# ══════════════════════════════════════════════════════════════════
def _serialize(p):
    dt = _payment_date(p)
    return {
        "id":                    p.id,
        "visit_id":              p.visit_id,
        "patient_name":          p.patient_name,
        "case_number":           p.case_number,
        "mobile":                p.mobile,
        "treatment_description": p.treatment_description,
        "fee":                   p.fee or 0,
        "discount":              p.discount or 0,
        "paid_amount":           p.paid_amount or 0,
        "balance":               p.balance or 0,
        "payment_method":        p.payment_method,
        "receipt_number":        p.receipt_number,
        "payment_date":          dt.strftime("%Y-%m-%d") if dt else None,
        "created_at":            p.created_at.strftime("%d-%b-%Y %H:%M") if p.created_at else "",
        "is_partial":            (p.balance or 0) > 0,
    }


